const readline = require('readline');

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLines = [];

    rl.on('line', (line) => {
        inputLines.push(line);
        if (inputLines.length === 2) {
            rl.close();
        }
    });

    rl.on('close', () => {
        let str = inputLines[0];
        let char = inputLines[1];

        let found = false;
        let position = -1;

        // Use a for loop to search for the character in the string
        for (let i = 0; i < str.length; ++i) {
            if (str[i] === char) {
                found = true;
                position = i;
                break;
            }
        }

        // Print the result using if-else
        if (found) {
            console.log(position);
        } else {
            console.log("-1");
        }
    });
}

